33	// Parse "<addr>" or "<hart>:<addr>", where addr supports 0x prefix
34	[[nodiscard]]
35	inline auto parse_reset_vector(const std::string_view s) -> reset_vector_spec
36	{
37	  auto str = std::string{s};
38	  try {
39	    auto colon = str.find(':');
40	    if (colon == std::string::npos)
41	      return {std::nullopt, std::stoull(str, nullptr, 0)};
42	    auto hart = std::stoull(str.substr(0, colon), nullptr, 0);
43	    auto addr = std::stoull(str.substr(colon + 1), nullptr, 0);
44	    return {hart, addr};
45	  } catch (...) {
46	    throw std::runtime_error("invalid --reset-vector: " + str
47	                             + " (expected <addr> or <hart>:<addr>)");
48	  }
49	}
