13	/**
14	 * A simple TLM2.0 socket width adapter that passes transactions through
15	 * without modification. Only changes the socket template width so that
16	 * sockets with different bus widths can be bound together.
17	 */
18	template<std::size_t TargetWidth, std::size_t InitiatorWidth>
19	class socket_width_adapter : public sc_core::sc_module,
20	                             public tlm::tlm_fw_transport_if<>,
21	                             public tlm::tlm_bw_transport_if<>
22	{
23	public:
24	  tlm::tlm_target_socket<TargetWidth> tsck{"tsck"};
25	  tlm::tlm_initiator_socket<InitiatorWidth> isck{"isck"};
26	
27	  socket_width_adapter(const sc_core::sc_module_name& name)
28	      : sc_core::sc_module{name}
29	  {
30	    tsck.bind(*this);
31	    isck.bind(*this);
32	  }
33	
34	private:
35	  void b_transport(tlm::tlm_generic_payload& trans,
36	                   sc_core::sc_time& t) override
37	  {
38	    spdlog::debug("[{}] b_transport: {} addr={:#x} len={}", name(),
39	                  trans.is_read() ? "read" : "write", trans.get_address(),
40	                  trans.get_data_length());
41	    isck->b_transport(trans, t);
42	  }
43	
44	  tlm::tlm_sync_enum nb_transport_fw(tlm::tlm_generic_payload& trans,
45	                                     tlm::tlm_phase& phase,
46	                                     sc_core::sc_time& t) override
47	  {
48	    spdlog::debug("[{}] nb_transport_fw: {} addr={:#x} len={}", name(),
49	                  trans.is_read() ? "read" : "write", trans.get_address(),
50	                  trans.get_data_length());
51	    return isck->nb_transport_fw(trans, phase, t);
52	  }
53	
54	  bool get_direct_mem_ptr(tlm::tlm_generic_payload& trans,
55	                          tlm::tlm_dmi& dmi) override
56	  {
57	    spdlog::debug("[{}] get_direct_mem_ptr: addr={:#x}", name(),
58	                  trans.get_address());
59	    return isck->get_direct_mem_ptr(trans, dmi);
60	  }
61	
62	  unsigned transport_dbg(tlm::tlm_generic_payload& trans) override
63	  {
64	    spdlog::debug("[{}] transport_dbg: addr={:#x} len={}", name(),
65	                  trans.get_address(), trans.get_data_length());
