87	/**
88	 * A TLM2.0 bus-width size converter that splits wide transactions into
89	 * multiple narrower ones.
90	 *
91	 * Example: size_converter<256, 64> converts 256-bit (32-byte) bus transactions
92	 * into multiple 64-bit (8-byte) transactions.
93	 *
94	 * Usage:
95	 *   size_converter<256, 64> conv{"conv"};
96	 *   interconnect.bind_initiator(conv.target_socket);  // CPU side (wide)
97	 *   interconnect_narrow.bind_target(conv.initiator_socket, region); // or
98	 * direct bind
99	 */
100	template<std::size_t InputWidth, std::size_t OutputWidth>
101	class size_converter : public sc_core::sc_module
102	{
103	  static_assert(InputWidth > OutputWidth,
104	                "InputWidth must be greater than OutputWidth");
105	  static_assert(InputWidth % OutputWidth == 0,
106	                "InputWidth must be a multiple of OutputWidth");
107	
108	  static constexpr std::size_t input_bytes = InputWidth / 8;
109	  static constexpr std::size_t output_bytes = OutputWidth / 8;
110	
111	public:
112	  tlm_utils::simple_target_socket<size_converter, InputWidth> target_socket{
113	    "target_socket"};
114	
115	  tlm_utils::simple_initiator_socket<size_converter, OutputWidth>
116	    initiator_socket{"initiator_socket"};
117	
118	  size_converter(const sc_core::sc_module_name& name)
119	      : sc_core::sc_module{name}
120	  {
121	    this->target_socket.register_b_transport(this,
122	                                             &size_converter::b_transport);
123	    this->target_socket.register_transport_dbg(this,
124	                                               &size_converter::transport_dbg);
125	    this->target_socket.register_get_direct_mem_ptr(
126	      this, &size_converter::get_direct_mem_ptr);
127	  }
128	
129	private:
130	  void b_transport(tlm::tlm_generic_payload& trans, sc_core::sc_time& delay)
131	  {
132	    const auto addr = trans.get_address();
133	    const auto len = trans.get_data_length();
134	    auto* ptr = trans.get_data_ptr();
135	    const auto cmd = trans.get_command();
136	    const auto byte_enable_len = trans.get_byte_enable_length();
137	    const auto* byte_enable_ptr = trans.get_byte_enable_ptr();
138	
139	    // If the transaction already fits in the output width, just forward it
140	    if (len <= output_bytes) {
141	      this->initiator_socket->b_transport(trans, delay);
142	      return;
143	    }
144	
145	    spdlog::debug("size_converter: splitting {} of {} bytes at {:#x}",
146	                  cmd == tlm::TLM_READ_COMMAND ? "read" : "write", len, addr);
147	
148	    // Split into multiple narrower transactions
149	    tlm::tlm_generic_payload sub_trans;
150	    sub_trans.set_command(cmd);
151	    sub_trans.set_streaming_width(
152	      trans.get_streaming_width()
153	        ? std::min(trans.get_streaming_width(), (unsigned) output_bytes)
154	        : output_bytes);
155	
156	    uint64_t offset = 0;
157	    while (offset < len) {
158	      const auto chunk = std::min<uint64_t>(output_bytes, len - offset);
159	
160	      sub_trans.set_address(addr + offset);
161	      sub_trans.set_data_ptr(ptr + offset);
162	      sub_trans.set_data_length(chunk);
163	
164	      if (byte_enable_len > 0 && byte_enable_ptr) {
165	        sub_trans.set_byte_enable_ptr(
166	          const_cast<uint8_t*>(byte_enable_ptr + offset));
167	        sub_trans.set_byte_enable_length(chunk);
168	      } else {
169	        sub_trans.set_byte_enable_ptr(nullptr);
170	        sub_trans.set_byte_enable_length(0);
171	      }
172	
173	      sub_trans.set_response_status(tlm::TLM_INCOMPLETE_RESPONSE);
174	
175	      this->initiator_socket->b_transport(sub_trans, delay);
176	
177	      if (sub_trans.get_response_status() != tlm::TLM_OK_RESPONSE) {
178	        trans.set_response_status(sub_trans.get_response_status());
179	        return;
180	      }
181	
182	      offset += chunk;
183	    }
184	
185	    trans.set_response_status(tlm::TLM_OK_RESPONSE);
186	  }
187	
188	  unsigned transport_dbg(tlm::tlm_generic_payload& trans)
189	  {
190	    const auto addr = trans.get_address();
191	    const auto len = trans.get_data_length();
192	    auto* ptr = trans.get_data_ptr();
193	
194	    if (len <= output_bytes)
195	      return this->initiator_socket->transport_dbg(trans);
196	
197	    tlm::tlm_generic_payload sub_trans;
198	    sub_trans.set_command(trans.get_command());
199	
200	    unsigned total = 0;
201	    uint64_t offset = 0;
202	    while (offset < len) {
203	      const auto chunk = std::min<uint64_t>(output_bytes, len - offset);
204	      sub_trans.set_address(addr + offset);
205	      sub_trans.set_data_ptr(ptr + offset);
206	      sub_trans.set_data_length(chunk);
207	      sub_trans.set_response_status(tlm::TLM_INCOMPLETE_RESPONSE);
208	
209	      total += this->initiator_socket->transport_dbg(sub_trans);
210	      offset += chunk;
211	    }
212	    return total;
213	  }
214	
215	  bool get_direct_mem_ptr(tlm::tlm_generic_payload& trans,
216	                          tlm::tlm_dmi& dmi_data)
217	  {
218	    return this->initiator_socket->get_direct_mem_ptr(trans, dmi_data);
219	  }
220	};
