11	// Dump/load a byte buffer using two gzip chunks.
12	// gzwrite accepts at most 2^31-1 bytes per call, so large buffers are split.
13	
14	inline void dump_gz_memory(const std::span<const uint8_t> mem,
15	                           const std::string& path)
16	{
17	  const size_t half = mem.size() / 2;
18	  const struct
19	  {
20	    const char* suffix;
21	    size_t offset;
22	    size_t size;
23	  } chunks[] = {{".0", 0, half}, {".1", half, mem.size() - half}};
24	
25	  for (const auto& c: chunks) {
26	    gzFile f = gzopen((path + c.suffix).c_str(), "wb");
27	    if (!f)
28	      throw std::runtime_error("Failed to open for writing: " + path
29	                               + c.suffix);
30	    gzwrite(f, mem.data() + c.offset, c.size);
31	    gzclose(f);
32	  }
33	}
34	
35	inline void load_gz_memory(const std::span<uint8_t> mem,
36	                           const std::string& path)
37	{
38	  const size_t half = mem.size() / 2;
39	  const struct
40	  {
41	    const char* suffix;
42	    size_t offset;
43	    size_t size;
44	  } chunks[] = {{".0", 0, half}, {".1", half, mem.size() - half}};
45	
46	  for (const auto& c: chunks) {
47	    gzFile f = gzopen((path + c.suffix).c_str(), "rb");
48	    if (!f)
49	      throw std::runtime_error("Failed to open for reading: " + path
50	                               + c.suffix);
51	    gzread(f, mem.data() + c.offset, c.size);
52	    gzclose(f);
53	  }
54	}
