15	// Owns a host file mapped into memory and exposes it as std::span<uint8_t>.
16	// Used by hybrid mode to back vsim's main RAM with a file shared with QEMU.
17	class MmapBacking
18	{
19	public:
20	  MmapBacking(const std::string& path, std::size_t size) : size_(size)
21	  {
22	    fd_ = ::open(path.c_str(), O_RDWR | O_CREAT, 0600);
23	    if (fd_ < 0)
24	      throw std::runtime_error("MmapBacking: open(" + path
25	                               + ") failed: " + std::strerror(errno));
26	    if (::ftruncate(fd_, static_cast<off_t>(size_)) != 0) {
27	      auto err = std::strerror(errno);
28	      ::close(fd_);
29	      fd_ = -1;
30	      throw std::runtime_error("MmapBacking: ftruncate failed: "
31	                               + std::string{err});
32	    }
33	    void* p = ::mmap(nullptr, size_, PROT_READ | PROT_WRITE, MAP_SHARED, fd_,
34	                     0);
35	    if (p == MAP_FAILED) {
36	      auto err = std::strerror(errno);
37	      ::close(fd_);
38	      fd_ = -1;
39	      throw std::runtime_error("MmapBacking: mmap failed: " + std::string{err});
40	    }
41	    base_ = static_cast<uint8_t*>(p);
42	  }
43	
44	  ~MmapBacking()
45	  {
46	    if (base_ != nullptr)
47	      ::munmap(base_, size_);
48	    if (fd_ >= 0)
49	      ::close(fd_);
50	  }
